cassandra().poll {
    connect {
       servers = listOf("localhost:7777", "10.42.42.42:7778")
       keyspace = "test_keyspace"
       datacenterProfile = DriverProfile.LOCAL
       datacenterName = "test_datacenter"
   }
   query("test")
   parameters(listOf(1, "two"))
   tieBreaker {
       name = "name"
       type = GenericType.STRING
   }
    pollDelay(Duration.ofSeconds(1))
    monitoring {
        meters = true
        events = false
   }
   broadcast(123, Duration.ofSeconds(20))
}

 cassandra().save {
    connect {
       servers = listOf("localhost:7777", "10.42.42.42:7778")
       keyspace = "test_keyspace"
       datacenterProfile = DriverProfile.LOCAL
       datacenterName = "test_datacenter"
   }
    tableName = tableName
    columnsConfig = columns
    rowsFactory = rowsFactory
    monitoring {
        meters = true
        events = false
   }
}

cassandra().search {
connect {
       servers = listOf("localhost:7777", "10.42.42.42:7778")
       keyspace = "test_keyspace"
       datacenterProfile = DriverProfile.LOCAL
       datacenterName = "test_datacenter"
}
   query("test")
   parameters(listOf(1, "two"))
   tieBreaker {
       name = "name"
       type = GenericType.STRING
    }
    monitoring {
        meters = true
        events = false
   }
}

elasticsearch().poll {
    index("building-moves")
    client {
        RestClient.builder(HttpHost("localhost", esPort, "http")).build()
    }
   query {
       """{
           "query": {
               "term": {
                   "action": "IN"
            }
        },
        "size": 2,
        "sort":["timestamp","username"]
    }""".trimIndent()
   }
   pollDelay(Duration.ofSeconds(1))
}

elasticsearch().save {
    documentsFactory = documentsFactory
    client{
        RestClient.builder(HttpHost("localhost", esPort, "http")).build()
    }
	monitoring {
	    events = false
        meters = true
    }
}

elasticsearch().search {
    client(clientBuilder)
    mapper(mapperConfigurer)
    index(indicesFactory)
    query(queryFactory)
    queryParameters(paramsFactory)
    monitoring {
        all()
    }
         fetchAll()

influxdb().poll {
    name = "poll.in"
    connect {
        server("http://localhost:8080", BUCKET, ORGANIZATION)
        basic("user", "passpasspass")
    }
    query("from(bucket: \"$BUCKET\") |> range(start: 0) |> filter(fn: (r) => (r[\"tag\"] == \"IN\") |> sort([\”_time\”], desc: false")
    pollDelay(Duration.ofSeconds(1))
}

influxdb().save {
   connect {
        server(
           url = "http://localhost:8080",
           bucket = "test",
           org = "testtesttest"
           )
         basic(
           user = "user",
           password  = "passpasspass"
           )
    }
    query {
        bucket = bucketName
        organization = orgName
        points = pointSupplier
    }
    monitoring {
        events = true
        meters = false
    }
}

influxdb().search {
connect {
   InfluxDBClientKotlinFactory.create(
       InfluxDBClientOptions.builder()
           .url("http://localhost:8080")
           .authenticate(“username”, “password”.toCharArray())
           .org(“organizationName”)
           .build()
   )
}
search {
   connectionConfig = { _, _ -> influxDbSearchStepConnectionImpl }
   query = { _, _ -> "query" }
}
monitoring {
   events = true
   meters = false
}
}

jackson().csvToMap {
   classpath(file)
   header {
       escapeChar('E')
       quoteChar('"')
       columnSeparator(';')
       withHeader()
       allowComments()

       column("1st value").double()
       column("2th value").string().array(",")
       column("3rd value").string(true)
       column("4th value").string(true)
   }
}
jackson().csvToObject(PojoForTest::class) {
   classpath(file)
}

jackson().xmlToObject(PojoForTest::class) {
   classpath(file)
}

jackson().jsonToMap() {
   classpath(file)
}
jackson().jsonToObject(PojoForTest::class) {
   classpath(file)
}

.jms()
    .consume {
        queues("queue-1")
        queueConnection { ActiveMQConnectionFactory().createQueueConnection() }
        monitoring {
            events = true
            meters = true
        }
    }.deserialize(JmsJsonDeserializer(User::class))

.jms().produce {
    records { ctx, input ->
        listOf(
            JmsProducerRecord(
                destination = ActiveMQQueue().createDestination("queue-1"),
                messageType = JmsMessageType.TEXT,
                value = "hello-queue"
            ),
            JmsProducerRecord(
                destination = ActiveMQQueue().createDestination("queue-1"),
                messageType = JmsMessageType.AUTO,
                value = "another message".toByteArray()
            )
        )
    }
    connect { ActiveMQConnectionFactory().createQueueConnection() }
        monitoring {
            events = true
            meters = true
        }
}

kafka().produce(
   Serdes.ByteArray().serializer(),
   Serdes.String().serializer()
) {
   name = "kafka-producer"
   bootstrap(bootstrap)
   clientName("producer")
   records { _, input ->
       listOf(
           KafkaProducerRecord(
               topic = producerTopic,
               value = "Produced ${input.record.value!!}"
           )
       )
   }
        monitoring {
            events = true
            meters = false
        }
}

mongodb().poll {
  connect {
MongoClients.create("mongodb://localhost:${mongoDbPort}/?streamType=netty")
  }
  search {
    database = "the-db"
    collection = "moves"
    query = Document().append("action", "IN")
    sort = linkedMapOf("timestamp" to Sorting.ASC)
    tieBreaker = "timestamp"
  }
  pollDelay(Duration.ofSeconds(2))
}

mongodb().save {
  connect {
    MongoClients.create()
  }
  query {
    database = databaseName
    collection = collectionName
    records = recordSupplier
  }
	monitoring {
	  events = false
    meters = true
  }
}

mongodb().search {
	connect {
    MongoClients.create()
  }
  search {
    database = { _, _ -> "db" }
    collection = { _, _ -> "col" }
    query = { _, _ -> Document() }
    sort = { _, _ -> linkedMapOf("asc" to Sorting.ASC, "desc" to Sorting.DESC) }
  }
  monitoring {
	  events = false
    meters = true
  }
}

netty().http {
   request { context, input -> SimpleHttpRequest(HttpMethod.HEAD, "/head") }
   connect {
       url("https://my-website.com:8080/test")
       connectTimeout = Duration.ofSeconds(5)
       inflate()
       charset(Charsets.ISO_8859_1)
       maxContentLength(123)
       followRedirections(15)
       noDelay = false
       keepConnectionAlive = false
       tls {
           disableCertificateVerification = true
       }
       proxy {
           type = HttpProxyType.SOCKS5
           address("my-proxy", 9876)
       }
       followRedirections(5)
   }
   pool {
       size = 143
       checkHealthBeforeUse = true
   }
   monitoring {
       events = true
       meters = true
   }
}.deserialize(String::class)

