r2dbcJasync().poll {
	protocol(Protocol. POSTGRESQL)
	connection {
 		port = 5432
 		username = "dbuser"
		password = "dbpassword"
		database = "thedatabase"
	}

	query("""select username, "timestamp" from buildingentries where action = ? order by "timestamp"""")
		parameters("ENTERING")
		pollDelay(Duration.ofSeconds(1))
		monitoring {
			events = false
            meters = true
		}
    }

listitem.programlisting:
r2dbcJasync().save {
	protocol(Protocol. POSTGRESQL)
	connection {
 		port = 5432
 		username = "dbuser"
		password = "dbpassword"
		database = "thedatabase"
	}
	tableName{ ctx, input -> "my_table" }
	columns{ ctx, input -> listOf("firstname", "surname", "registration") }
	values{ ctx, input -> list(
        JasyncSaveRecord("john", "doe", "265edfg2g5"),
        JasyncSaveRecord("alice", "foo", "3763gdw8"),
        JasyncSaveRecord("bob", "bar", "627twh762")
    )}
	monitoring {
	  	events = false
        meters = true
    }
}

r2dbcJasync().search {
	protocol(Protocol. POSTGRESQL)
	connection {
 		port = 5432
 		username = "dbuser"
		password = "dbpassword"
		database = "thedatabase"
	}
	query { ctx, input -> """select username, "timestamp" from buildingentries where action = ? order by "timestamp"""" }
	parameters { ctx, input -> listOf("ENTERING") }

	monitoring {
	  	events = false
    	meters = true
    }
}

rabbitmq().
  consume {
    queue("user")
    connection {
      host = hostContainer
      port = portContainer
      password = "defaultpass"
      username = "user"
    }
    concurrency(2)
    prefetchCount (11)
}

rabbitmq().
  produce {
    name = "my-producer-step"
    concurrency(10)
    connection {
      host = "anotherhost"
      port = 5673
      password = "pass"
      username = "test"
      virtualHost = "/guest"
      clientProperties = mapOf("t" to "test")
      }
    records(recordSupplier)
    monitoring {
      events = true
      meters = false
    }
}

.redisLettuce()
  pollHscan {
    name = "poll.hscanacl"
    connection {
      nodes = “localhost:6379”
      database = 0
      redisConnectionType = RedisConnectionType.CLUSTER
      authPassword = "pass"
      authUser = "user"
    }
    KeyOrPattern("hscan-test-acl")
    pollDelay(Duration.ofSeconds(1))
    monitoring {
      events = false
      meters = false
    }
  }

.redisLettuce().save {
  name = "save"
  connection {
    nodes = “localhost:6379”
    database = 0
    redisConnectionType = RedisConnectionType.SINGLE
    authPassword = "password"
    authUser = "user"
  }
  records { _, _ ->
    listOf(
      ValueRecord(
        key = "key",
        value = "value"
      ),
      HashRecord(
        key = "hash",
        value = mapOf("key" to "value")
      )
    )
  }
  monitoring {
    events = true
    meters = true
  }
}

.redisLettuce()
  .streamsConsume {
    name = "consumer"
    connection {
      nodes = “localhost:6379”
      database = 0
      redisConnectionType = RedisConnectionType.CLUSTER
      authPassword = "password"
      authUser = "user"
    }
    concurrency(5)
    group("consumer-test-1")
    streamKey("test")
    offset(“FROM_BEGINNING”)
    monitoring {
      events = false
      meters = false
    }
  }

.redisLettuce().streamsProduce {
  name = "producer"
  connection {
    nodes = “localhost:6379”
    database = 0
    redisConnectionType = RedisConnectionType.CLUSTER
    authPassword = "password"
    authUser = "user"
  }
  records { _, input ->
    listOf(
      LettuceStreamsProduceRecord(
        key = "producer.test",
        value = mapOf("test" to input.value.values.first())
        )
      )
  }
  monitoring {
    events = true
    meters = true
  }
}
